+                .clipShape(Circle())
+        } else {
+            self.avatarPlaceholder
+                .frame(width: 20, height: 20)
+        }
+    }
+
+    private var avatarPlaceholder: some View {
+        Circle()
+            .fill(Color(nsColor: .separatorColor))
+            .overlay(
+                Image(systemName: "arrow.turn.down.right")
+                    .font(.system(size: 10))
+                    .foregroundStyle(.secondary)
+            )
